-- Reports
then SUBSTRING(cus.cCusAbbName,CHARINDEX(''('', cus.cCusAbbName)+1, CHARINDEX('')'', cus.cCusAbbName)-1-CHARINDEX(''('', cus.cCusAbbName)) --cus.cCusAbbName 
else cus.cCusAbbName end as ''CusAbbName''
,cus.ccusperson,wh.cwhcode,wh.cWhName,inv.cInvCode,inv.cInvName,inv.cinvstd,dls.iquantity,dls.iNum,dls.iTaxUnitPrice,dls.iSum,dl.cVerifier,dl.cshipAddress 
from DispatchList as dl
LEFT JOIN DispatchLists as dls on dl.dlid = dls.DLID
LEFT JOIN Customer as cus on cus.ccuscode = dl.cCusCode
LEFT JOIN Inventory as inv on inv.cInvCode = dls.cInvCode
LEFT JOIN InventoryClass as invcls on inv.cInvCCode = invcls.cInvCCode
LEFT JOIN DistrictClass as dc on cus.cDCCode = dc.cDCCode
LEFT JOIN WareHouse as wh on wh.cWhCode = dls.cWhCode
where 1 = 1', 'main', FALSE, 'published', FALSE, NOW(), 1, NOW(), 1);
,case when (CHARINDEX(''('', cus.cCusAbbName)>0 and  CHARINDEX('')'', cus.cCusAbbName)>0 ) 
		then SUBSTRING(cus.cCusAbbName,CHARINDEX(''('', cus.cCusAbbName)+1, CHARINDEX('')'', cus.cCusAbbName)-1-CHARINDEX(''('', cus.cCusAbbName))
		else cus.cCusAbbName end as ''客户简称'',dl.cShipAddress as ''发货地址''
,cus.cCusPerson as ''联系人'',wh.cWhName as ''仓库'',
invtopcls.cInvCName as ''存货顶级分类'',inv.cInvName ''存货名称'',invcls.cInvCCode as ''存货分类编码'',invcls.cInvCName as ''存货分类'',
iQuantity as ''数量'',iNum as ''件数'',isum as ''金额''
from DispatchList as dl LEFT JOIN DispatchLists as dls on dl.dlid = dls.DLID
LEFT JOIN Inventory as inv on inv.cinvcode = dls.cInvCode 
LEFT JOIN ComputationUnit as cu on inv.cComUnitCode = cu.cComunitCode
LEFT JOIN Customer as cus on cus.ccuscode = dl.cCusCode
LEFT JOIN Person as p on p.cpersoncode = dl.cPersonCode
LEFT JOIN DistrictClass as dc on dc.cdccode = cus.cdccode
LEFT JOIN InventoryClass as invcls on invcls.cinvccode = inv.cinvccode
LEFT JOIN InventoryClass as invtopcls on left(invcls.cInvCCode,2) = invtopcls.cInvCCode
LEFT JOIN Warehouse as wh on wh.cWhCode = dls.cWhCode
where 1 = 1 --and dc.cDCName like ''%济南%''
', 'main', FALSE, 'published', FALSE, NOW(), 1, NOW(), 1);
,case when (CHARINDEX(''('', cus.cCusAbbName)>0 and  CHARINDEX('')'', cus.cCusAbbName)>0 ) 
		then SUBSTRING(cus.cCusAbbName,CHARINDEX(''('', cus.cCusAbbName)+1, CHARINDEX('')'', cus.cCusAbbName)-1-CHARINDEX(''('', cus.cCusAbbName))
		else cus.cCusAbbName end as ''客户简称''
,cus.cCusPerson as ''联系人'','''' as ''仓库'',
invtopcls.cInvCName as ''存货顶级分类'',inv.cInvName ''存货名称'',invcls.cInvCCode as ''存货分类编码'',invcls.cInvCName as ''存货分类'',
iQuantity as ''数量'',isum as ''金额''
from SO_SOMain as som LEFT JOIN SO_SODetails as sod on som.id = sod.ID
LEFT JOIN Inventory as inv on inv.cinvcode = sod.cInvCode 
LEFT JOIN ComputationUnit as cu on inv.cComUnitCode = cu.cComunitCode
LEFT JOIN Customer as cus on cus.ccuscode = som.cCusCode
LEFT JOIN Person as p on p.cpersoncode = som.cPersonCode
LEFT JOIN DistrictClass as dc on dc.cdccode = cus.cdccode
LEFT JOIN InventoryClass as invcls on invcls.cinvccode = inv.cinvccode
LEFT JOIN InventoryClass as invtopcls on left(invcls.cInvCCode,2) = invtopcls.cInvCCode
where 1 = 1 and dc.cDCName not like ''%济南%''', 'main', FALSE, 'published', FALSE, NOW(), 1, NOW(), 1);
select dl.ddate as ''日期'',dl.cdlcode as ''发货单号'',dl.cCusName as ''客户名称''
,wh.cwhcode as ''仓库编码'',wh.cWhName as ''仓库名称'',inv.cInvCode as ''存货编码'',inv.cInvName as ''存货名称'',inv.cinvstd as ''型号''
,dls.iquantity as ''数量'',dls.iNum as ''件数'',(
select case when (0<>( SELECT top 1 CASE   WHEN isnull(iNum,0)<>0 --当结存数量不为0时，计算存货成本
THEN isnull(iMoney,0)/iNum ELSE 0 END FROM  dbo.IA_Summary
WHERE cInvCode = dls.cinvcode AND cWhCode = dls.cwhcode order by IA_Summary.iMonth desc))
then (SELECT top 1 CASE WHEN isnull(iNum,0)<>0 --当结存数量不为0时，计算存货成本
THEN isnull(iMoney,0)/iNum ELSE 0 END  FROM  dbo.IA_Summary
WHERE  (1 = 1) AND (cInvCode = dls.cinvcode) AND (cWhCode = dls.cwhcode) order by IA_Summary.iMonth desc)
ELSE (select top 1 ISNULL(rds.iUnitCost,0) from rdrecord as rd --取存货最后一次入库成本
left join rdrecords as rds on rd.id = rds.id
where brdflag = 1 and rds.cinvcode = dls.cinvcode and rd.cwhcode = dls.cwhcode
order by rd.ddate desc ) END )AS  ''成本单价'',(
select dls.iQuantity * case when (0<>( SELECT top 1 CASE 
WHEN isnull(iNum,0)<>0 --当结存数量不为0时，计算存货成本
THEN isnull(iMoney,0)/iNum ELSE 0 END FROM  dbo.IA_Summary
WHERE  (1 = 1) AND (cInvCode = dls.cinvcode) AND (cWhCode = dls.cwhcode) order by IA_Summary.iMonth desc))
then (SELECT top 1 CASE WHEN isnull(iNum,0)<>0 --当结存数量不为0时，计算存货成本
THEN isnull(iMoney,0)/iNum ELSE 0 END FROM  dbo.IA_Summary
WHERE  (1 = 1) AND (cInvCode = dls.cinvcode) AND (cWhCode = dls.cwhcode) order by IA_Summary.iMonth desc)
ELSE (select top 1 ISNULL(rds.iUnitCost,0) from rdrecord as rd --取存货最后一次入库成本
left join rdrecords as rds on rd.id = rds.id where brdflag = 1 and rds.cinvcode = dls.cinvcode and rd.cwhcode = dls.cwhcode
order by rd.ddate desc ) END )AS  ''成本''
from DispatchList as dl
LEFT JOIN DispatchLists as dls on dl.dlid = dls.DLID
LEFT JOIN Customer as cus on cus.ccuscode = dl.cCusCode
LEFT JOIN Inventory as inv on inv.cInvCode = dls.cInvCode
LEFT JOIN InventoryClass as invcls on inv.cInvCCode = invcls.cInvCCode
LEFT JOIN DistrictClass as dc on cus.cDCCode = dc.cDCCode
LEFT JOIN Warehouse as wh on wh.cwhcode = dls.cWhCode
where 1 = 1
and year(dl.ddate) = year(getdate())', 'main', FALSE, 'published', FALSE, NOW(), 1, NOW(), 1);
,wh.cwhName,invcls.cInvCName,inv.cInvStd,dls.iquantity
from DispatchList as dl
LEFT JOIN DispatchLists as dls on dl.dlid = dls.DLID
