LEFT JOIN DistrictClass as dc on cus.cDCCode = dc.cDCCode
LEFT JOIN WareHouse as wh on wh.cWhCode = dls.cWhCode
where 1 = 1', 'main', FALSE, 'published', FALSE, NOW(), 1, NOW(), 1);
